@page "/board"
@using sv_6587358a86df45c4bd42b55c752d43de
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (_loading)
{
    <div class="alert alert-info">Loading tasks…</div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">@_errorMessage</div>
}
else
{
    <BoardSummary Tasks="@_tasks" />

    <BoardSearchBar SearchTerm="@_searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3 mt-2">
        @foreach (var col in _columns)
        {
            var filtered = FilteredTasks(col);
            var canMoveLeft = Array.IndexOf(_columns, col) > 0;
            var canMoveRight = Array.IndexOf(_columns, col) < _columns.Length - 1;

            <div class="col-md-4">
                <BoardColumn ColumnName="@col"
                             Tasks="@filtered"
                             CanMoveLeft="@canMoveLeft"
                             CanMoveRight="@canMoveRight"
                             OnMoveLeft="@(t => MoveTask(t, -1))"
                             OnMoveRight="@(t => MoveTask(t, 1))"
                             OnTaskCreated="@OnTaskCreated" />
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
    private List<TaskItem> _tasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> FilteredTasks(string status)
    {
        return _tasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchTerm) ||
                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
            .ToList();
    }

    private void OnSearchChanged(string term) => _searchTerm = term;

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = Array.IndexOf(_columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= _columns.Length) return;

        var newStatus = _columns[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            _tasks = _tasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task OnTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _tasks.Add(created with { Status = args.Status });
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

@using sv_6587358a86df45c4bd42b55c752d43de

<div class="d-flex flex-wrap gap-3 mb-3">
    <span class="badge bg-primary fs-6">Total: @Tasks.Count</span>
    <span class="badge bg-secondary fs-6">To Do: @Tasks.Count(t => t.Status == "To Do")</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @Tasks.Count(t => t.Status == "In Progress")</span>
    <span class="badge bg-success fs-6">Done: @Tasks.Count(t => t.Status == "Done")</span>
    <span class="badge bg-danger fs-6">Overdue: @Tasks.Count(t => t.DueDate < DateTime.Today)</span>
</div>

@code {
    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();
}

@using sv_6587358a86df45c4bd42b55c752d43de

<div class="card h-100">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>@ColumnName</strong>
        <span class="badge bg-secondary">@Tasks.Count</span>
    </div>
    <div class="card-body d-flex flex-column gap-2">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="@task"
                      CanMoveLeft="@CanMoveLeft"
                      CanMoveRight="@CanMoveRight"
                      OnMoveLeft="@OnMoveLeft"
                      OnMoveRight="@OnMoveRight" />
        }
    </div>
    <div class="card-footer">
        @if (_showForm)
        {
            <AddTaskForm ColumnStatus="@ColumnName"
                         OnSave="@HandleSave"
                         OnCancel="@(() => _showForm = false)" />
        }
        else
        {
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => _showForm = true">
                + Add Task
            </button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnTaskCreated { get; set; }

    private bool _showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        await OnTaskCreated.InvokeAsync(args);
        _showForm = false;
    }
}

@using sv_6587358a86df45c4bd42b55c752d43de

<div class="card shadow-sm">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task)">
                    ← Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task)">
                    Move Right →
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

