@page "/board"
@using sv_6587358a86df45c4bd42b55c752d43de
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (_loading)
{
    <div class="alert alert-info">Loading tasks…</div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">@_errorMessage</div>
}
else
{
    <BoardSummary Tasks="@_tasks" />

    <BoardSearchBar SearchTerm="@_searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3 mt-2">
        @foreach (var col in _columns)
        {
            var filtered = FilteredTasks(col);
            var canMoveLeft = Array.IndexOf(_columns, col) > 0;
            var canMoveRight = Array.IndexOf(_columns, col) < _columns.Length - 1;

            <div class="col-md-4">
                <BoardColumn ColumnName="@col"
                             Tasks="@filtered"
                             CanMoveLeft="@canMoveLeft"
                             CanMoveRight="@canMoveRight"
                             OnMoveLeft="@(t => MoveTask(t, -1))"
                             OnMoveRight="@(t => MoveTask(t, 1))"
                             OnTaskCreated="@OnTaskCreated" />
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
    private List<TaskItem> _tasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> FilteredTasks(string status)
    {
        return _tasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchTerm) ||
                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
            .ToList();
    }

    private void OnSearchChanged(string term) => _searchTerm = term;

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = Array.IndexOf(_columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= _columns.Length) return;

        var newStatus = _columns[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            _tasks = _tasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task OnTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _tasks.Add(created with { Status = args.Status });
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

